/** Minimal EnumSet shim — CloudStream defines its own. */
class EnumSet<T : Enum<T>> private constructor(
    private val set: MutableSet<T> = mutableSetOf()
) : Set<T> by set {
    fun add(element: T): Boolean = set.add(element)
    fun addAll(elements: Collection<T>): Boolean = set.addAll(elements)

    companion object {
        @JvmStatic fun <T : Enum<T>> noneOf(clazz: Class<T>): EnumSet<T> = EnumSet()
        @JvmStatic fun <T : Enum<T>> of(value: T): EnumSet<T> =
            EnumSet<T>().also { it.add(value) }
    }
}

enum class DubStatus {
    None,
    Dubbed,
    Subbed
}
